    geo_result_label:"косинусна слиčност (1024D)",
    geo_interp_identical:"Готово идентичне",
    geo_interp_identical_text:"Ове реченице деле готово исто значење. У преводилачком смислу, то је готово савршено подударање.",
    geo_interp_similar:"Веома слиčне",
    geo_interp_similar_text:"Јако семантичко преклапање. Реченице обрађују исту тему са сличним оквиром.",
    geo_interp_related:"Повезане",
    geo_interp_related_text:"Умерено повезане. Деле неке концепте, али се разликују у фокусу или формулацији.",
    geo_interp_loose:"Слабо повезане",
